import { useEffect, useState } from "react";
import axios from "axios";

function Leads() {
    const [data, setData] = useState({});
    const [showDecrypted, setShowDecrypted] = useState(true);

    const fetchLeads = async (decrypted = true) => {
        try {
            const res = await axios.get("http://localhost:8000/leads", {
                params: { decrypted: decrypted ? 1 : 0 },
            });
            setData(res.data || {});
        } catch (err) {
            console.error("Error fetching leads:", err);
        }
    };

    useEffect(() => {
        fetchLeads(showDecrypted);
    }, [showDecrypted]);

    return (
        <div className="container mt-4">
            <div className="d-flex justify-content-between align-items-center mb-4">
                <h3>📋 Leads Data</h3>
                <button
                    className="btn btn-primary btn-sm"
                    onClick={() => setShowDecrypted((prev) => !prev)}
                >
                    {showDecrypted ? "🔒 Show Encrypted" : "🔑 Show Decrypted"}
                </button>
            </div>

            {/* ---------------- TABLE 1 ---------------- */}
            <div className="mb-5">
                <h5>Table: tbltemp_dncleads_tracker</h5>
                {data.tbltemp_dncleads_tracker?.length > 0 ? (
                    <table className="table table-bordered table-hover">
                        <thead className="table-dark">
                            <tr>
                                <th>First</th><th>Last</th><th>Email</th><th>Phone</th>
                                <th>Company</th><th>Domain</th><th>Campaign</th>
                                <th>Date</th><th>Followed By</th>
                            </tr>
                        </thead>
                        <tbody>
                            {data.tbltemp_dncleads_tracker.map((lead) => (
                                <tr key={lead.id}>
                                    <td>{lead.first_name}</td>
                                    <td>{lead.last_name}</td>
                                    <td>{lead.email}</td>
                                    <td>{lead.phone}</td>
                                    <td>{lead.company}</td>
                                    <td>{lead.domain}</td>
                                    <td>{lead.campaign}</td>
                                    <td>{lead.date}</td>
                                    <td>{lead.followed_by}</td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                ) : <p>No rows found.</p>}
            </div>

